        # keep distance from opponent but also bias toward center
        center_dx = abs(nx - (w-1)//2) + abs(ny - (h-1)//2)
        score = -d_opp * 2 - center_dx
        if score > best_score:
            best_score = score
            best = (dx, dy)
    if best is not None:
        return [best[0], best[1]]

    return [0, 0]
